{"content":"import {
  World,
  Mesh,
  Group,
  BoxGeometry,
  PlaneGeometry,
  SphereGeometry,
  CylinderGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  Color,
  Vector3,
  AmbientLight,
  PointLight,
  DirectionalLight,
  Fog,
  AdditiveBlending,
  DoubleSide,
  LineSegments,
  EdgesGeometry,
  LineBasicMaterial,
  BufferGeometry,
  Float32BufferAttribute,
  PanelUI,
  Follower,
  ScreenSpace,
} from '@iwsdk/core';

import { GameSystem } from './game-system.js';
import { UISystem } from './ui-system.js';

async function main() {
  const container = document.getElementById('app')!;

  const world = await World.create(container, {
    xr: { offer: 'once' as const },
    render: {
      fov: 75,
      near: 0.1,
      far: 200,
      defaultLighting: false,
      camera: { position: [0, 1.6, 0], lookAt: [0, 1.5, -10] },
    },
    input: { canvasPointerEvents: true },
    features: {
      locomotion: false,
      grabbing: false,
      physics: false,
    },
  });

  // Scene atmosphere
  world.scene.background = new Color(0x000811);
  world.scene.fog = new Fog(0x000811, 30, 100);

  // Lighting
  const ambient = new AmbientLight(0x112244, 0.3);
  world.scene.add(ambient);

  const dirLight = new DirectionalLight(0x4488ff, 0.4);
  dirLight.position.set(0, 10, -5);
  world.scene.add(dirLight);

  // Cyan point lights along the corridor
  for (let i = 0; i < 6; i++) {
    const pl = new PointLight(0x00ffff, 1.5, 30);
    pl.position.set(i % 2 === 0 ? -4 : 4, 3, -i * 15);
    world.scene.add(pl);
  }

  // Build the static corridor structure
  buildCorridor(world);

  // Register systems
  world.registerSystem(GameSystem);
  world.registerSystem(UISystem);

  // Get system instances and set up refs
  const gameSystem = world.getSystem(GameSystem)!;
  const uiSystem = world.getSystem(UISystem)!;

  // Create PanelUI entities
  const menuEntity = world.createTransformEntity(undefined, {
    parent: world.playerHeadEntity,
    persistent: true,
  });
  menuEntity.addComponent(PanelUI, { config: './ui/main-menu.json' });
  menuEntity.addComponent(Follower, {
    offsetPosition: [0, 0, -2.5],
    smoothing: 6,
  });

  const hudEntity = world.createTransformEntity(undefined, {
    parent: world.playerHeadEntity,
    persistent: true,
  });
  hudEntity.addComponent(PanelUI, { config: './ui/hud.json' });
  hudEntity.addComponent(Follower, {
    offsetPosition: [0, -0.7, -2],
    smoothing: 8,
  });

  const gameOverEntity = world.createTransformEntity(undefined, {
    parent: world.playerHeadEntity,
    persistent: true,
  });
  gameOverEntity.addComponent(PanelUI, { config: './ui/game-over.json' });
  gameOverEntity.addComponent(Follower, {
    offsetPosition: [0, 0, -2.5],
    smoothing: 6,
  });

  const pauseEntity = world.createTransformEntity(undefined, {
    parent: world.playerHeadEntity,
    persistent: true,
  });
  pauseEntity.addComponent(PanelUI, { config: './ui/pause-menu.json' });
  pauseEntity.addComponent(Follower, {
    offsetPosition: [0, 0.1, -2.2],
    smoothing: 6,
  });

  const modeSelectEntity = world.createTransformEntity(undefined, {
    parent: world.playerHeadEntity,
    persistent: true,
  });
  modeSelectEntity.addComponent(PanelUI, { config: './ui/mode-select.json' });
  modeSelectEntity.addComponent(Follower, {
    offsetPosition: [0, 0, -2.5],
    smoothing: 6,
  });

  const settingsEntity = world.createTransformEntity(undefined, {
    parent: world.playerHeadEntity,
    persistent: true,
  });
  settingsEntity.addComponent(PanelUI, { config: './ui/settings.json' });
  settingsEntity.addComponent(Follower, {
    offsetPosition: [0, 0, -2.5],
    smoothing: 6,
  });

  const achievementsEntity = world.createTransformEntity(undefined, {
    parent: world.playerHeadEntity,
    persistent: true,
  });
  achievementsEntity.addComponent(PanelUI, { config: './ui/achievements.json' });
  achievementsEntity.addComponent(Follower, {
    offsetPosition: [0, 0.1, -2.5],
    smoothing: 6,
  });

  const tutorialEntity = world.createTransformEntity(undefined, {
    parent: world.playerHeadEntity,
    persistent: true,
  });
  tutorialEntity.addComponent(PanelUI, { config: './ui/tutorial.json' });
  tutorialEntity.addComponent(Follower, {
    offsetPosition: [0, 0, -2.5],
    smoothing: 6,
  });

  const countdownEntity = world.createTransformEntity(undefined, {
    parent: world.playerHeadEntity,
    persistent: true,
  });
  countdownEntity.addComponent(PanelUI, { config: './ui/countdown.json' });
  countdownEntity.addComponent(Follower, {
    offsetPosition: [0, 0.2, -2],
    smoothing: 10,
  });

  const newRecordEntity = world.createTransformEntity(undefined, {
    parent: world.playerHeadEntity,
    persistent: true,
  });
  newRecordEntity.addComponent(PanelUI, { config: './ui/new-record.json' });
  newRecordEntity.addComponent(Follower, {
    offsetPosition: [0, 0.4, -2],
    smoothing: 8,
  });

  // Pass references to systems
  gameSystem.setRefs({ world, uiSystem });
  uiSystem.setRefs({ gameSystem });
}

function buildCorridor(world: World) {
  const corridorWidth = 8;
  const wallHeight = 4;
  const corridorLength = 120;

  // Floor - dark base
  const floorGeo = new PlaneGeometry(corridorWidth, corridorLength);
  const floorMat = new MeshStandardMaterial({
    color: 0x001122,
    emissive: 0x001133,
    emissiveIntensity: 0.2,
  });
  const floor = new Mesh(floorGeo, floorMat);
  floor.rotation.x = -Math.PI / 2;
  floor.position.set(0, 0, -corridorLength / 2 + 10);
  world.scene.add(floor);

  // Grid lines on the floor
  const gridGroup = new Group();
  const gridMat = new LineBasicMaterial({ color: 0x00ffff, transparent: true, opacity: 0.25 });

  // Longitudinal lines
  for (let x = -corridorWidth / 2; x <= corridorWidth / 2; x += 1) {
    const geo = new BufferGeometry();
    geo.setAttribute('position', new Float32BufferAttribute([
      x, 0.005, 10,
      x, 0.005, -corridorLength + 10,
    ], 3));
    gridGroup.add(new LineSegments(geo, gridMat));
  }

  // Lateral lines
  for (let z = 10; z >= -corridorLength + 10; z -= 2) {
    const geo = new BufferGeometry();
    geo.setAttribute('position', new Float32BufferAttribute([
      -corridorWidth / 2, 0.005, z,
      corridorWidth / 2, 0.005, z,
    ], 3));
    gridGroup.add(new LineSegments(geo, gridMat));
  }
  world.scene.add(gridGroup);

  // Lane divider lines (brighter)
  const laneMat = new LineBasicMaterial({ color: 0x00ffff, transparent: true, opacity: 0.5 });
  for (const xPos of [-2, 2]) {
    const geo = new BufferGeometry();
    geo.setAttribute('position', new Float32BufferAttribute([
      xPos, 0.01, 10,
      xPos, 0.01, -corridorLength + 10,
    ], 3));
    world.scene.add(new LineSegments(geo, laneMat));
  }

  // Walls
  const wallMat = new MeshStandardMaterial({
    color: 0x001133,
    emissive: 0x0044aa,
    emissiveIntensity: 0.3,
    transparent: true,
    opacity: 0.12,
    side: DoubleSide,
  });

  for (const side of [-1, 1]) {
    const wallGeo = new PlaneGeometry(corridorLength, wallHeight);
    const wall = new Mesh(wallGeo, wallMat);
    wall.position.set(side * corridorWidth / 2, wallHeight / 2, -corridorLength / 2 + 10);
    wall.rotation.y = side * Math.PI / 2;
    world.scene.add(wall);

    // Wall edge trim (bright neon line at base)
    const trimGeo = new BufferGeometry();
    trimGeo.setAttribute('position', new Float32BufferAttribute([
      side * corridorWidth / 2, 0.01, 10,
      side * corridorWidth / 2, 0.01, -corridorLength + 10,
    ], 3));
    const trimMat = new LineBasicMaterial({ color: 0x0088ff, transparent: true, opacity: 0.8 });
    world.scene.add(new LineSegments(trimGeo, trimMat));

    // Top edge trim
    const topTrimGeo = new BufferGeometry();
    topTrimGeo.setAttribute('position', new Float32BufferAttribute([
      side * corridorWidth / 2, wallHeight, 10,
      side * corridorWidth / 2, wallHeight, -corridorLength + 10,
    ], 3));
    world.scene.add(new LineSegments(topTrimGeo, trimMat));
  }

  // Decorative ceiling crossbeams
  const beamMat = new MeshStandardMaterial({
    color: 0x002244,
    emissive: 0x0066cc,
    emissiveIntensity: 0.4,
    transparent: true,
    opacity: 0.3,
  });
  for (let z = 5; z >= -corridorLength + 10; z -= 10) {
    const beamGeo = new BoxGeometry(corridorWidth, 0.1, 0.1);
    const beam = new Mesh(beamGeo, beamMat);
    beam.position.set(0, wallHeight, z);
    world.scene.add(beam);
  }
}

