  MeshBasicMaterial,
  Color,
  Vector3,
  AdditiveBlending,
  InputComponent,
} from '@iwsdk/core';

import type { UISystem } from './ui-system.js';

// ── Constants ─────────────────────────────────────────────────

const LANE_WIDTH = 2;
const LANE_POSITIONS = [-LANE_WIDTH, 0, LANE_WIDTH];
const BASE_SPEED = 10;
const MAX_SPEED = 45;
const SPEED_INCREASE_RATE = 0.12;
const LANE_SWITCH_SPEED = 14;
const LANE_SWITCH_COOLDOWN = 0.12;
const SPAWN_Z = -90;
const DESPAWN_Z = 12;
const INITIAL_LIVES = 3;
const INVINCIBILITY_TIME = 1.8;
const ORB_BASE_SCORE = 100;
const DISTANCE_SCORE_RATE = 10;
const MAX_MULTIPLIER = 10;
const MULTIPLIER_DECAY_TIME = 2.5;
const OBSTACLE_BASE_INTERVAL = 1.4;
const OBSTACLE_MIN_INTERVAL = 0.35;
const COLLECTIBLE_INTERVAL = 0.6;

// ── Types ─────────────────────────────────────────────────────

export enum GameState {
  MENU = 'menu',
  MODE_SELECT = 'mode_select',
  SETTINGS = 'settings',
  ACHIEVEMENTS = 'achievements',
  TUTORIAL = 'tutorial',
  COUNTDOWN = 'countdown',
  PLAYING = 'playing',
  PAUSED = 'paused',
  GAME_OVER = 'game_over',
}

export enum GameMode {
  CLASSIC = 'classic',
  SPRINT = 'sprint',
  TIME_ATTACK = 'time_attack',
  ZEN = 'zen',
  ENDLESS = 'endless',
  CHALLENGE = 'challenge',
}

export interface GameModeConfig {
  name: string;
  description: string;
  lives: number;
  hasObstacles: boolean;
  timeLimit: number; // 0 = no limit
  targetDistance: number; // 0 = no target
  speedMultiplier: number;
}

export const GAME_MODES: Record<GameMode, GameModeConfig> = {
  [GameMode.CLASSIC]: {
    name: 'Classic',
    description: '3 lives - survive as far as you can',
    lives: 3,
    hasObstacles: true,
    timeLimit: 0,
    targetDistance: 0,
    speedMultiplier: 1,
  },
  [GameMode.SPRINT]: {
    name: 'Sprint',
    description: 'Race to 2000m as fast as possible',
    lives: 1,
    hasObstacles: true,
    timeLimit: 0,
    targetDistance: 2000,
    speedMultiplier: 1.3,
  },
  [GameMode.TIME_ATTACK]: {
    name: 'Time Attack',
    description: '90 seconds - maximize your distance',
    lives: 99,
    hasObstacles: true,
    timeLimit: 90,
    targetDistance: 0,
    speedMultiplier: 1.1,
  },
  [GameMode.ZEN]: {
    name: 'Zen',
